import React, { useState } from "react";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";
import API from "../api";
import { useNavigate } from "react-router-dom";

function ResultPage() {
  const navigate = useNavigate();
  const result = JSON.parse(localStorage.getItem("prediction_result"));
  const user = JSON.parse(localStorage.getItem("user"));

  const [appointmentDate, setAppointmentDate] = useState("");
  const [notes, setNotes] = useState("");
  const [booking, setBooking] = useState(false);

  if (!result) {
    return (
      <div className="dashboard-layout">
        <Sidebar role="patient" />
        <div className="main-content">
          <Navbar title="Prediction Result" subtitle="No result found" />
          <div className="dashboard-card text-center py-5">
            <h3 className="mb-3">No Prediction Result Found</h3>
            <p className="text-muted mb-4">
              Please submit the prediction form first.
            </p>
            <button
              className="btn btn-premium"
              onClick={() => navigate("/prediction")}
            >
              Go to Prediction Form
            </button>
          </div>
        </div>
      </div>
    );
  }

  const doctor = result?.doctor_details || {};
  const confidence = Number(result?.confidence || 0);
  const symptomCount = Number(result?.selected_symptoms_count || 0);

  const getSeverity = () => {
    if (symptomCount >= 7 || confidence >= 85) return "High";
    if (symptomCount >= 4 || confidence >= 60) return "Moderate";
    return "Mild";
  };

  const severity = getSeverity();

  const downloadPDF = async () => {
    try {
      const response = await API.get(`/generate-pdf/${result.report_id}`, {
        responseType: "blob"
      });

      const blob = new Blob([response.data], { type: "application/pdf" });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `doctor_report_${result.report_id}.pdf`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
    } catch (error) {
      alert("PDF download failed");
    }
  };

  const handlePrint = () => {
    window.print();
  };

  const bookAppointment = async () => {
    if (!appointmentDate) {
      alert("Please select appointment date");
      return;
    }

    try {
      setBooking(true);

      await API.post("/appointments", {
        patient_name: user?.name,
        patient_email: user?.email,
        doctor_name: result?.doctor_name,
        specialization: result?.specialization,
        appointment_date: appointmentDate,
        notes
      });

      alert("Appointment requested successfully");
      setAppointmentDate("");
      setNotes("");
    } catch (error) {
      alert(error.response?.data?.error || "Appointment request failed");
    } finally {
      setBooking(false);
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role="patient" />

      <div className="main-content">
        <Navbar
          title="Prediction Result"
          subtitle="AI doctor recommendation generated successfully"
        />

        <div className="row g-4">
          <div className="col-lg-8">
            <div className="result-box">
              <div className="d-flex justify-content-between align-items-center flex-wrap gap-2 mb-4">
                <span className="badge bg-success fs-6 px-3 py-2 rounded-pill">
                  AI Result Ready
                </span>

                <span className="badge bg-primary fs-6 px-3 py-2 rounded-pill">
                  Report ID: #{result?.report_id}
                </span>
              </div>

              <h5 className="text-muted mb-2">Recommended Doctor</h5>
              <h2 className="text-primary fw-bold mb-1">{result?.doctor_name}</h2>
              <p className="lead mb-4">{result?.specialization}</p>

              <div className="row">
                <div className="col-md-6 mb-3">
                  <div className="border rounded-4 p-3 h-100 bg-light">
                    <small className="text-muted d-block mb-1">Predicted Disease</small>
                    <h5 className="mb-0 text-capitalize">{result?.predicted_disease}</h5>
                  </div>
                </div>

                <div className="col-md-6 mb-3">
                  <div className="border rounded-4 p-3 h-100 bg-light">
                    <small className="text-muted d-block mb-1">Patient Name</small>
                    <h5 className="mb-0">{result?.patient_name}</h5>
                  </div>
                </div>
              </div>

              <div className="row mt-1">
                <div className="col-md-6 mb-3">
                  <div className="border rounded-4 p-3 h-100 bg-light">
                    <small className="text-muted d-block mb-1">Severity</small>
                    <h5 className="mb-0">{severity}</h5>
                  </div>
                </div>

                <div className="col-md-6 mb-3">
                  <div className="border rounded-4 p-3 h-100 bg-light">
                    <small className="text-muted d-block mb-1">Selected Symptoms</small>
                    <h5 className="mb-0">{symptomCount}</h5>
                  </div>
                </div>
              </div>

              <div className="mt-4 mb-4">
                <div className="d-flex justify-content-between align-items-center mb-2">
                  <strong>Confidence Score</strong>
                  <span className="fw-bold text-primary">{confidence}%</span>
                </div>

                <div className="progress" style={{ height: "24px", borderRadius: "20px" }}>
                  <div
                    className="progress-bar progress-bar-striped progress-bar-animated"
                    role="progressbar"
                    style={{
                      width: `${confidence}%`,
                      borderRadius: "20px"
                    }}
                  >
                    {confidence}%
                  </div>
                </div>
              </div>

              <div className="alert alert-info rounded-4 border-0">
                <h6 className="mb-2">AI Recommendation Summary</h6>
                <p className="mb-0">
                  Based on the selected symptoms, the AI model predicts that the
                  patient should consult a <strong>{result?.specialization}</strong>.
                  The most suitable recommendation is <strong>{result?.doctor_name}</strong>.
                </p>
              </div>

              <div className="d-flex gap-3 mt-4 flex-wrap">
                <button className="btn btn-premium px-4" onClick={downloadPDF}>
                  Download PDF Report
                </button>

                <button className="btn btn-outline-dark px-4" onClick={handlePrint}>
                  Print Preview
                </button>

                <button
                  className="btn btn-outline-primary px-4"
                  onClick={() => navigate("/prediction")}
                >
                  Predict Again
                </button>
              </div>
            </div>

            <div className="dashboard-card mt-4">
              <h4 className="mb-3">Book Appointment</h4>

              <div className="row">
                <div className="col-md-6 mb-3">
                  <label>Appointment Date</label>
                  <input
                    type="date"
                    className="form-control"
                    value={appointmentDate}
                    onChange={(e) => setAppointmentDate(e.target.value)}
                  />
                </div>

                <div className="col-md-6 mb-3">
                  <label>Notes</label>
                  <input
                    type="text"
                    className="form-control"
                    placeholder="Optional note"
                    value={notes}
                    onChange={(e) => setNotes(e.target.value)}
                  />
                </div>
              </div>

              <button className="btn btn-premium" onClick={bookAppointment} disabled={booking}>
                {booking ? "Booking..." : "Request Appointment"}
              </button>
            </div>
          </div>

          <div className="col-lg-4">
            <div className="dashboard-card mb-4 text-center">
              <img
                src={
                  doctor?.photo
                    ? doctor.photo
                    : "https://via.placeholder.com/200x200?text=Doctor"
                }
                alt={result?.doctor_name}
                className="rounded-circle mb-3"
                style={{ width: "140px", height: "140px", objectFit: "cover" }}
              />

              <h4 className="mb-1">{result?.doctor_name}</h4>
              <p className="text-muted mb-0">{result?.specialization}</p>
            </div>

            <div className="dashboard-card mb-4">
              <h5 className="mb-3">Doctor Details</h5>
              <p className="mb-2"><strong>Experience:</strong> {doctor?.experience || "N/A"}</p>
              <p className="mb-2"><strong>Fees:</strong> {doctor?.fees || "N/A"}</p>
              <p className="mb-2"><strong>Hospital:</strong> {doctor?.hospital || "N/A"}</p>
              <p className="mb-0"><strong>About:</strong> {doctor?.description || "N/A"}</p>
            </div>

            <div className="dashboard-card mb-4">
              <h5 className="mb-3">AI Confidence Insight</h5>

              {confidence >= 85 && (
                <div className="alert alert-success rounded-4 mb-0">
                  High confidence prediction. This recommendation is strongly matched.
                </div>
              )}

              {confidence >= 60 && confidence < 85 && (
                <div className="alert alert-warning rounded-4 mb-0">
                  Moderate confidence prediction. Doctor consultation is recommended.
                </div>
              )}

              {confidence < 60 && (
                <div className="alert alert-danger rounded-4 mb-0">
                  Low confidence prediction. Please verify with a medical professional.
                </div>
              )}
            </div>

            <div className="dashboard-card">
              <h5 className="mb-3">Prediction Metadata</h5>
              <p className="mb-2"><strong>Report ID:</strong> #{result?.report_id}</p>
              <p className="mb-2"><strong>Doctor:</strong> {result?.doctor_name}</p>
              <p className="mb-2"><strong>Specialization:</strong> {result?.specialization}</p>
              <p className="mb-0"><strong>Confidence:</strong> {confidence}%</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ResultPage;
